//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Row properties: height, pagination, header repeat, hidden rows".
//!
//! Each `#[test]` encodes a Word-compliance constraint for `CT_TrPr` /
//! `CT_TrPrBase` row-level properties (gridBefore/gridAfter, wBefore/wAfter,
//! tblCellSpacing, tblHeader, trHeight, cantSplit, hidden, trPrChange order).
//!
//! A FAILING assertion encodes a REAL Word-compliance gap in stemma: the engine
//! diverges from what Microsoft Word does on open / save / accept / reject.
//! Do NOT "fix" a failure by weakening the assertion — a fail is the finding.
//!
//! Methodology (consumption vs. save): stemma round-trips UNTOUCHED content
//! byte-verbatim. So `reserialize()` of an unedited document reflects stemma's
//! verbatim-preservation contract, NOT Word's render-time normalization.
//! `xmlContains`/`xmlOmits` on `reserialize()` are valid for markup the
//! serializer actively rebuilds (tables are ALWAYS rebuilt from the typed model,
//! never passed through verbatim) and for opens-clean validity — but never for
//! "Word ignores value V on layout". Consumption semantics are asserted on the
//! READ side (`read_accepted`/`read_rejected().to_text()`).

use stemma::ExportOptions;
use stemma::api::{Document, validate};

// ─── Prelude: minimal-.docx plumbing (mirrors the shared spec-suite prelude) ─

/// Build a valid minimal `.docx`. `body_xml` is the inner content of `<w:body>`
/// (callers supply their own `<w:sectPr/>`). `extra_parts` are additional parts
/// keyed by archive path (e.g. `("word/styles.xml", "<...>")`); for each we add
/// a `[Content_Types].xml` Override using a best-effort content-type guess.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Base content types + an Override per extra part.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (path, _) in extra_parts {
        let ct = if path.ends_with("styles.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        } else if path.ends_with("numbering.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        } else {
            "application/xml"
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{path}" ContentType="{ct}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (path, content) in extra_parts {
            zip.start_file(*path, opts).unwrap();
            zip.write_all(content.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let reader = std::io::Cursor::new(docx);
    let mut zip = zip::ZipArchive::new(reader).expect("open zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present in archive");
    let mut out = String::new();
    use std::io::Read;
    file.read_to_string(&mut out).expect("read document.xml");
    out
}

/// Parse, serialize (the verbatim/rebuild path the serializer produces), and
/// return the resulting `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Assert that `stemma::api::validate` reports no errors, with a self-explanatory
/// message embedding the rule + refs.
fn assert_opens_clean(bytes: &[u8], rule_refs: &str) {
    let report = validate(bytes);
    assert!(
        report.ok,
        "{rule_refs} — expected validate() to report no errors (opens clean in Word), but got issues: {:?}",
        report.issues
    );
}

