#[test]
fn row_gridbefore_gridafter_opens_clean_and_preserved() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="5000" w:type="dxa"/></w:tblPr><w:tblGrid><w:gridCol w:w="2500"/><w:gridCol w:w="2500"/></w:tblGrid><w:tr><w:trPr><w:gridBefore w:val="1"/><w:gridAfter w:val="1"/></w:trPr><w:tc><w:tcPr><w:tcW w:w="2500" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "gridBefore/gridAfter are declared CT_TrPrBase children (ISO 29500-1 §17.4.15/§17.4.14, ECMA-376 Annex A CT_TrPrBase, MS-OI29500 §2.1.129/§2.1.128); a row carrying positive grid offsets is schema-valid and must open clean",
    );
}

