#[test]
fn trpr_base_choice_then_trprchange_sequence_opens_clean() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:trPr><w:tblHeader/><w:trHeight w:val="720" w:hRule="atLeast"/><w:trPrChange w:id="1" w:author="a" w:date="2024-01-01T00:00:00Z"><w:trPr><w:trHeight w:val="500" w:hRule="atLeast"/></w:trPr></w:trPrChange></w:trPr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Row</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p/><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "CT_TrPr = unbounded CT_TrPrBase choice + trailing ins/del/trPrChange sequence (ECMA-376 Annex A; ISO 29500-1 §17.4.81/§17.13.5.37/§17.4.80); reordered base members with a correctly-trailing trPrChange are schema-valid, so Word opens clean and validate() reports no errors",
    );
}

#[test]
fn trpr_wbefore_wafter_roundtrip_verbatim_and_opens_clean() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:trPr><w:wBefore w:w="720" w:type="dxa"/><w:wAfter w:w="360" w:type="dxa"/></w:trPr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Row</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p/><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "wBefore/wAfter are declared CT_TrPrBase children of type CT_TblWidth (ECMA-376 Annex A; ISO 29500-1 §17.4.81/§17.4.86/§17.4.87); a row carrying them is schema-valid and Word opens it without repair",
    );
    let xml = reserialize(&b);
    assert!(
        xml.contains("<w:wBefore"),
        "ISO 29500-1 §17.4.86: stemma's contract for an unedited row must preserve the wBefore row property on re-serialize (valid trPr child Word would keep); got document.xml: {xml}"
    );
    assert!(
        xml.contains("<w:wAfter"),
        "ISO 29500-1 §17.4.87: an unedited wAfter must survive re-serialization (valid trPr child Word would keep); got document.xml: {xml}"
    );
}

#[test]
fn cantsplit_survives_table_roundtrip() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:trPr><w:cantSplit/></w:trPr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Keep on one page</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains("<w:cantSplit"),
        "ISO 29500-1 §17.4.6 / §17.4.81 / Annex A CT_TrPrBase: cantSplit is a row property Word preserves on save; stemma rebuilds the table row from its model on every serialize, so the rebuilt trPr must re-emit cantSplit or the keep-together semantic is silently lost; got document.xml: {xml}"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.4.81 / Annex A CT_TrPrBase: cantSplit is a valid trPr child, so the round-tripped document must open without repair",
    );
}

#[test]
fn hidden_row_marker_survives_table_roundtrip() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:trPr><w:hidden/></w:trPr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Hidden row content</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains("<w:hidden"),
        "ISO 29500-1 §17.4.20: the hidden row marker is preserved by Word on save; stemma rebuilds the row from its model on serialize, so the rebuilt trPr must re-emit w:hidden or the row is silently un-hidden; got document.xml: {xml}"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.4.81 / §17.17.4 / Annex A CT_TrPrBase: w:hidden is a valid CT_OnOff trPr child, so the round-tripped document must open without repair",
    );
}

