#[test]
fn hidden_and_cantsplit_coexist_ct_trprbase_order_clean() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:trPr><w:cantSplit/><w:hidden/></w:trPr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>secret</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.4.6 + §17.4.20 + Annex A CT_TrPrBase: cantSplit then hidden are both valid CT_TrPrBase children in schema order; opens clean",
    );
    let doc = Document::parse(&b).expect("parse");
    let reject_text = doc.read_rejected().expect("read_rejected").to_text();
    assert_eq!(
        reject_text.trim(),
        "secret",
        "ISO 29500-1 §17.4.20: hidden is display-only, not a tracked deletion — the row's text is still present in the read view even though the row is visually hidden"
    );
}
